input.command:
cd /tmp && cat > skf-astgrep-probe.ts <<'EOF'
export const myConst = 42;
export const myArrow = (a: number): number => a + 1;
export function myFunc(a: number): number { return a; }
export class MyClass { x = 1; }
export interface MyIface { x: number; }
export type MyType = string | number;
export enum MyEnum { A, B, C }
EOF
echo "=== export const \$NAME = \$VALUE ==="
ast-grep run -p 'export const $NAME = $VALUE' -l typescript --json=stream skf-astgrep-probe.ts | grep -o '"text":"export [a-z]* [A-Za-z]*' || echo "(no output)"
echo "=== export function \$NAME(\$\$\$PARAMS) ==="
ast-grep run -p 'export function $NAME($$$PARAMS)' -l typescript --json=stream skf-astgrep-probe.ts | grep -o '"text":"export [a-z]* [A-Za-z]*' || echo "(no output)"
echo "=== export class \$NAME ==="
ast-grep run -p 'export class $NAME' -l typescript --json=stream skf-astgrep-probe.ts | grep -o '"text":"export [a-z]* [A-Za-z]*' || echo "(no output)"
echo "=== export interface \$NAME { \$\$\$ } ==="
ast-grep run -p 'export interface $NAME { $$$ }' -l typescript --json=stream skf-astgrep-probe.ts | grep -o '"text":"export [a-z]* [A-Za-z]*' || echo "(no output)"
echo "=== export type \$NAME ==="
ast-grep run -p 'export type $NAME' -l typescript --json=stream skf-astgrep-probe.ts | grep -o '"text":"export [a-z]* [A-Za-z]*' || echo "(no output)"
echo "=== export enum \$NAME ==="
ast-grep run -p 'export enum $NAME' -l typescript --json=stream skf-astgrep-probe.ts | grep -o '"text":"export [a-z]* [A-Za-z]*' || echo "(no output)"

cd /tmp && cat > skf-astgrep-probe2.ts <<'EOF'
export interface Simple { x: number; }
export interface Generic<T> { value: T; }
export interface Extended extends Base { y: number; }
export interface Multi {
  a: string;
  b: number;
}
export interface Empty {}
EOF
echo "=== export interface \$NAME { \$\$\$ } (variants) ==="
ast-grep run -p 'export interface $NAME { $$$ }' -l typescript --json=stream skf-astgrep-probe2.ts 2>&1 | grep -o '"text":"export interface [A-Za-z]*' || echo "(no matches)"
echo ""
echo "=== bare: export interface \$NAME ==="
ast-grep run -p 'export interface $NAME' -l typescript --json=stream skf-astgrep-probe2.ts 2>&1 | grep -oE '(ERROR node|"text":"export interface [A-Za-z]*)' || echo "(no matches)"
echo ""
echo "=== type alias variants: type \$NAME = \$T (no export kw) ==="
printf 'export type A = string;\ntype B = number;\n' > t2.ts
ast-grep run -p 'type $NAME = $T' -l typescript --json=stream t2.ts 2>&1 | grep -oE '(ERROR node|"text":"[a-z ]*type [A-Za-z]*)' || echo "(no matches)"

